use std::env;
use std::fs;

struct Case {
    name: &'static str,
    packed: bool,
    group: bool,
    reuse: bool,
    seq: Vec<usize>,
    rows: Vec<Vec<i32>>,
}

fn cases() -> Vec<Case> {
