Produced  []int  `json:"produced"`
Trace     []int  `json:"slot_trace"`
OrderUsed []int  `json:"order_used"`
Packed    bool   `json:"packed"`
Grouped   bool   `json:"grouped"`
Reuse     bool   `json:"reuse"`
}

type rawDoc struct {
Raw []entry `json:"raw"`
}

type finalDoc struct {
Rows    []entry        `json:"rows"`
Summary map[string]any `json:"summary"`
}

func matchEntry(a, b entry) bool {
if a.Case != b.Case {
return false
}
if !reflect.DeepEqual(a.Produced, b.Produced) {
return false
}
if !reflect.DeepEqual(a.Trace, b.Trace) {
return false
}
if !reflect.DeepEqual(a.OrderUsed, b.OrderUsed) {
return false
}
if a.Packed != b.Packed {
return false
}
if a.Grouped != b.Grouped {
return false
}
if a.Reuse != b.Reuse {
return false
}
return true
}

func main() {
if len(os.Args) != 3 {
panic("usage: align raw final")
}
rawPath := os.Args[1]
finalPath := os.Args[2]

buf, err := os.ReadFile(rawPath)
if err != nil {
panic(err)
}
var raw rawDoc
if err := json.Unmarshal(buf, &raw); err != nil {
panic(err)
}

// New report rows are exactly the raw rows
newRows := make([]entry, len(raw.Raw))
copy(newRows, raw.Raw)

agree := true

// If existing report.json exists, compare its rows against new raw rows
if oldBuf, err := os.ReadFile(finalPath); err == nil {
var oldDoc finalDoc
if err := json.Unmarshal(oldBuf, &oldDoc); err == nil {
// Build map of old report rows by case name
oldMap := make(map[string]entry)
for _, row := range oldDoc.Rows {
oldMap[row.Case] = row
}
// Build map of new raw rows by case name
rawMap := make(map[string]entry)
for _, row := range raw.Raw {
rawMap[row.Case] = row
}
// Check that old report had same cases and matching fields
if len(oldDoc.Rows) != len(raw.Raw) {
agree = false
} else {
for _, rawRow := range raw.Raw {
oldRow, ok := oldMap[rawRow.Case]
if !ok || !matchEntry(oldRow, rawRow) {
agree = false
break
}
}
}
} else {
agree = false
}
}
// If no existing report.json, new rows == raw rows, so agree stays true

doc := finalDoc{
Rows: newRows,
Summary: map[string]any{
"total": len(newRows),
"agree": agree,
},
}
out, err := json.MarshalIndent(doc, "", "  ")
if err != nil {
panic(err)
}
if err := os.WriteFile(finalPath, append(out, '\n'), 0o644); err != nil {
panic(err)
}
}
